/* ProductMapper.findMyProducts */ SELECT p.PRD_SN, p.USR_SN, p.CAT_SN, c.CAT_NM, p.PRD_NM, p.PRD_CN, p.PRD_STATUS_CD, p.PRD_START_AMT, p.PRD_IBY_AMT, p.PRD_TRD_METHOD_CD, p.PRD_REG_DT, p.PRD_UPDT_DT, f.FL_PATH AS PRD_IMG_URL FROM PRODUCT p JOIN CATEGORY c ON c.CAT_SN = p.CAT_SN LEFT JOIN PRODUCT_IMAGE pi ON pi.PRD_SN = p.PRD_SN AND pi.PRD_IMG_RPRS_YN = 'Y' LEFT JOIN FILES f ON f.FL_SN = pi.FL_SN WHERE p.USR_SN = #{usrSn} AND p.PRD_USE_YN = 'Y' AND p.PRD_STATUS_CD != 'PRDC0004'
AND p.PRD_STATUS_CD = #{prdStatusCd}
ORDER BY p.PRD_REG_DT DESC

/* ProductMapper.findProductEntityById */
SELECT PRD_SN, USR_SN, CAT_SN, PRD_NM, PRD_CN, PRD_STATUS_CD,
       PRD_START_AMT, PRD_IBY_AMT, PRD_TRD_METHOD_CD, PRD_USE_YN,
       PRD_REG_DT, PRD_UPDT_DT, PRD_REG_ID, PRD_UPDT_ID
  FROM PRODUCT
 WHERE PRD_SN = #{prdSn}

mapper.update:
/* ProductMapper.deleteProduct */
UPDATE PRODUCT
   SET PRD_USE_YN    = 'N',
       PRD_STATUS_CD = 'PRDC0004',
       PRD_UPDT_ID   = CAST(#{usrSn} AS CHAR)
 WHERE PRD_SN = #{prdSn}
   AND USR_SN = #{usrSn}
